#!/usr/bin/env node

import {
  mkdtemp,
  mkdir,
  readFile,
  readdir,
  rm,
  writeFile,
} from 'node:fs/promises';
import { tmpdir } from 'node:os';
import { basename, dirname, extname, join, resolve } from 'node:path';
import { spawn } from 'node:child_process';

function writeResponse(response) {
  process.stdout.write(JSON.stringify(response));
}

function writeError(value, stdout = '', stderr = '') {
  writeResponse({
    status: 'error',
    value,
    stdout,
    stderr,
  });
}

async function runCommand(command, args, options = {}) {
  return await new Promise((resolvePromise, rejectPromise) => {
    const child = spawn(command, args, {
      ...options,
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    let stdout = '';
    let stderr = '';

    child.stdout.on('data', (chunk) => {
      stdout += chunk.toString();
    });

    child.stderr.on('data', (chunk) => {
      stderr += chunk.toString();
    });

    child.on('error', rejectPromise);
    child.on('close', (code) => {
      resolvePromise({
        code: code ?? 1,
        stdout,
        stderr,
      });
    });
  });
}

async function listJavaSourceFiles(sourceDir, sourceFilePath) {
  const entries = await readdir(sourceDir, { withFileTypes: true });
  const files = [];

  for (const entry of entries) {
    if (!entry.isFile()) {
      continue;
    }

    const fullPath = join(sourceDir, entry.name);
    if (extname(entry.name) !== '.java') {
      continue;
    }

    if (entry.name.startsWith('.')) {
      continue;
    }

    files.push(fullPath);
  }

  if (!files.includes(sourceFilePath)) {
    files.push(sourceFilePath);
  }

  return files;
}

async function copyJavaSources(sourceDir, sourceFilePath, targetDir) {
  const sourceFiles = await listJavaSourceFiles(sourceDir, sourceFilePath);
  const copiedFiles = [];

  for (const filePath of sourceFiles) {
    const fileName = basename(filePath);
    const targetPath = join(targetDir, fileName);
    await writeFile(targetPath, await readFile(filePath, 'utf8'));
    copiedFiles.push(targetPath);
  }

  return copiedFiles;
}

