async function writeSpringWrapper(sourceRoot) {
  const wrapperPath = join(sourceRoot, 'XGnosisSpringCompatMain.java');
  await writeFile(
    wrapperPath,
    `import java.lang.annotation.Annotation;
import java.lang.reflect.Method;
import java.lang.reflect.Parameter;
import java.nio.charset.StandardCharsets;
import java.util.ArrayList;
import java.util.Base64;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.regex.Matcher;
import java.util.regex.Pattern;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.Controller;
import org.springframework.web.bind.annotation.DeleteMapping;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PatchMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestMethod;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.ResponseStatus;
import org.springframework.web.bind.annotation.RestController;

public final class XGnosisSpringCompatMain {
  private XGnosisSpringCompatMain() {}

  public static void main(String[] args) throws Exception {
    String controllerClassName = args[0];
    String requestPayload = new String(Base64.getDecoder().decode(args[1]), StandardCharsets.UTF_8);
    RequestEnvelope request = RequestEnvelope.parse(requestPayload);
    CompatibilityResponse response = dispatch(controllerClassName, request);
    System.out.print(response.toJson());
  }

  private static CompatibilityResponse dispatch(String controllerClassName, RequestEnvelope request) throws Exception {
    Class<?> controllerClass = Class.forName(controllerClassName);
    if (!controllerClass.isAnnotationPresent(RestController.class)
        && !controllerClass.isAnnotationPresent(Controller.class)) {
      throw new IllegalStateException("Spring compatibility requires @RestController or @Controller");
    }

    Object controller = controllerClass.getDeclaredConstructor().newInstance();
    String classPrefix = normalizePath(annotationPath(controllerClass.getAnnotation(RequestMapping.class)));

    for (Method method : controllerClass.getDeclaredMethods()) {
      RouteDescriptor route = RouteDescriptor.fromMethod(method, classPrefix);
      if (route == null || !route.supports(request.method)) {
        continue;
      }

      Map<String, String> pathVariables = route.match(request.path);
      if (pathVariables == null) {
        continue;
      }

      Object[] args = bindArguments(method.getParameters(), request, pathVariables);
      Object result = method.invoke(controller, args);
      int status = method.isAnnotationPresent(ResponseStatus.class)
          ? method.getAnnotation(ResponseStatus.class).value().value()
          : HttpStatus.OK.value();
      return CompatibilityResponse.fromResult(status, result);
    }

    return CompatibilityResponse.unmatched();
  }

  private static Object[] bindArguments(Parameter[] parameters, RequestEnvelope request, Map<String, String> pathVariables) {
    Object[] bound = new Object[parameters.length];

    for (int index = 0; index < parameters.length; index += 1) {
      Parameter parameter = parameters[index];
      if (parameter.isAnnotationPresent(PathVariable.class)) {
        String name = parameter.getAnnotation(PathVariable.class).value();
        bound[index] = coerce(pathVariables.get(name), parameter.getType());
        continue;
      }

      if (parameter.isAnnotationPresent(RequestParam.class)) {
        String name = parameter.getAnnotation(RequestParam.class).value();
        bound[index] = coerce(request.query.get(name), parameter.getType());
        continue;
      }

      if (parameter.isAnnotationPresent(RequestBody.class)) {
        bound[index] = coerce(request.body, parameter.getType());
        continue;
      }

      bound[index] = null;
    }

    return bound;
  }

  private static Object coerce(String value, Class<?> targetType) {
    if (targetType == String.class) {
      return value;
    }
    if (targetType == int.class || targetType == Integer.class) {
      return value == null ? 0 : Integer.parseInt(value);
    }
    if (targetType == long.class || targetType == Long.class) {
      return value == null ? 0L : Long.parseLong(value);
    }
    if (targetType == boolean.class || targetType == Boolean.class) {
      return value != null && Boolean.parseBoolean(value);
    }
    return value;
  }

  private static String annotationPath(RequestMapping mapping) {
    if (mapping == null) {
      return "";
    }
    if (!mapping.path().isEmpty()) {
      return mapping.path();
    }
    return mapping.value();
  }

  private static String normalizePath(String value) {
    if (value == null || value.isEmpty() || "/".equals(value)) {
      return "";
    }
    String normalized = value.startsWith("/") ? value : "/" + value;
    return normalized.endsWith("/") && normalized.length() > 1
        ? normalized.substring(0, normalized.length() - 1)
        : normalized;
  }

  private static final class RouteDescriptor {
    private final List<String> methods;
    private final String fullPath;
    private final Pattern pattern;
    private final List<String> variableNames;

    private RouteDescriptor(List<String> methods, String fullPath, Pattern pattern, List<String> variableNames) {
      this.methods = methods;
      this.fullPath = fullPath;
      this.pattern = pattern;
      this.variableNames = variableNames;
    }

    static RouteDescriptor fromMethod(Method method, String classPrefix) {
      String methodPath = "";
      List<String> methods = new ArrayList<>();

      if (method.isAnnotationPresent(GetMapping.class)) {
        methodPath = mappingPath(method.getAnnotation(GetMapping.class).path(), method.getAnnotation(GetMapping.class).value());
        methods.add("GET");
      } else if (method.isAnnotationPresent(PostMapping.class)) {
        methodPath = mappingPath(method.getAnnotation(PostMapping.class).path(), method.getAnnotation(PostMapping.class).value());
        methods.add("POST");
      } else if (method.isAnnotationPresent(PutMapping.class)) {
        methodPath = mappingPath(method.getAnnotation(PutMapping.class).path(), method.getAnnotation(PutMapping.class).value());
        methods.add("PUT");
      } else if (method.isAnnotationPresent(DeleteMapping.class)) {
        methodPath = mappingPath(method.getAnnotation(DeleteMapping.class).path(), method.getAnnotation(DeleteMapping.class).value());
        methods.add("DELETE");
      } else if (method.isAnnotationPresent(PatchMapping.class)) {
        methodPath = mappingPath(method.getAnnotation(PatchMapping.class).path(), method.getAnnotation(PatchMapping.class).value());
        methods.add("PATCH");
      } else if (method.isAnnotationPresent(RequestMapping.class)) {
        RequestMapping requestMapping = method.getAnnotation(RequestMapping.class);
        methodPath = mappingPath(requestMapping.path(), requestMapping.value());
        if (requestMapping.method().length == 0) {
          methods.add("GET");
        } else {
          for (RequestMethod requestMethod : requestMapping.method()) {
            methods.add(requestMethod.name());
          }
        }
      } else {
        return null;
      }

      String fullPath = normalizePath(classPrefix + normalizePath(methodPath));
      if (fullPath.isEmpty()) {
        fullPath = "/";
      }

      List<String> variableNames = new ArrayList<>();
      StringBuilder regex = new StringBuilder("^");
      Matcher matcher = Pattern.compile("\\\\{([A-Za-z_][A-Za-z0-9_]*)\\\\}").matcher(fullPath);
      int cursor = 0;
      while (matcher.find()) {
        regex.append(Pattern.quote(fullPath.substring(cursor, matcher.start())));
        regex.append("([^/]+)");
        variableNames.add(matcher.group(1));
        cursor = matcher.end();
      }
      regex.append(Pattern.quote(fullPath.substring(cursor)));
      regex.append("$");

      return new RouteDescriptor(methods, fullPath, Pattern.compile(regex.toString()), variableNames);
    }

    boolean supports(String method) {
      return methods.contains(method);
    }

    Map<String, String> match(String path) {
      Matcher matcher = pattern.matcher(path);
      if (!matcher.matches()) {
        return null;
      }

      Map<String, String> params = new LinkedHashMap<>();
      for (int index = 0; index < variableNames.size(); index += 1) {
        params.put(variableNames.get(index), matcher.group(index + 1));
      }
      return params;
    }

    private static String mappingPath(String path, String value) {
      return path != null && !path.isEmpty() ? path : value;
    }
  }

  private static final class RequestEnvelope {
    private final String method;
    private final String path;
    private final Map<String, String> query;
    private final String body;

    private RequestEnvelope(String method, String path, Map<String, String> query, String body) {
      this.method = method;
      this.path = path;
      this.query = query;
      this.body = body;
    }

    static RequestEnvelope parse(String payload) {
      Map<String, String> values = new LinkedHashMap<>();
      for (String line : payload.split("\\\\n")) {
        int separator = line.indexOf('=');
        if (separator < 0) {
          continue;
        }
        values.put(line.substring(0, separator), line.substring(separator + 1));
      }

      String method = values.getOrDefault("method", "GET");
      String path = values.getOrDefault("path", "/");
      String queryRaw = values.getOrDefault("query", "");
      String body = "";
      if (!values.getOrDefault("body", "").isEmpty()) {
        body = new String(Base64.getDecoder().decode(values.get("body")), StandardCharsets.UTF_8);
      }

      Map<String, String> query = new LinkedHashMap<>();
      if (!queryRaw.isEmpty()) {
        String normalized = queryRaw.startsWith("?") ? queryRaw.substring(1) : queryRaw;
        for (String pair : normalized.split("&")) {
          if (pair.isEmpty()) {
            continue;
          }
          String[] parts = pair.split("=", 2);
          query.put(parts[0], parts.length > 1 ? parts[1] : "");
        }
      }

      return new RequestEnvelope(method, path, query, body);
    }
  }

  private static final class CompatibilityResponse {
    private final boolean matched;
    private final int status;
    private final Map<String, String> headers;
    private final String body;

    private CompatibilityResponse(boolean matched, int status, Map<String, String> headers, String body) {
      this.matched = matched;
      this.status = status;
      this.headers = headers;
      this.body = body;
    }

    static CompatibilityResponse unmatched() {
      return new CompatibilityResponse(false, 404, new LinkedHashMap<>(), "");
    }

    static CompatibilityResponse fromResult(int status, Object result) {
      String body = result == null ? "" : result.toString();
      Map<String, String> headers = new LinkedHashMap<>();
      String trimmed = body.trim();
      if (trimmed.startsWith("{") || trimmed.startsWith("[")) {
        headers.put("Content-Type", "application/json; charset=utf-8");
      } else {
        headers.put("Content-Type", "text/plain; charset=utf-8");
      }
      return new CompatibilityResponse(true, status, headers, body);
    }

    String toJson() {
      StringBuilder json = new StringBuilder();
      json.append("{\\"matched\\":").append(matched);
      if (matched) {
        json.append(",\\"response\\":{");
        json.append("\\"status\\":").append(status).append(',');
        json.append("\\"headers\\":").append(stringMapToJson(headers)).append(',');
        json.append("\\"body\\":{");
        json.append("\\"encoding\\":\\"base64\\",");
        json.append("\\"value\\":\\"")
            .append(Base64.getEncoder().encodeToString(body.getBytes(StandardCharsets.UTF_8)))
            .append("\\"}}");
      }
      json.append('}');
      return json.toString();
    }

    private String stringMapToJson(Map<String, String> values) {
      StringBuilder json = new StringBuilder();
      json.append('{');
      boolean first = true;
      for (Map.Entry<String, String> entry : values.entrySet()) {
        if (!first) {
          json.append(',');
        }
        first = false;
        json.append(quote(entry.getKey())).append(':').append(quote(entry.getValue()));
      }
      json.append('}');
      return json.toString();
    }

    private String quote(String value) {
      StringBuilder escaped = new StringBuilder();
      for (int index = 0; index < value.length(); index += 1) {
        char current = value.charAt(index);
        switch (current) {
          case '\\\\':
            escaped.append("\\\\\\\\");
            break;
          case '"':
            escaped.append("\\\\\\"");
            break;
          case '\\n':
            escaped.append("\\\\n");
            break;
          case '\\r':
            escaped.append("\\\\r");
            break;
          default:
            escaped.append(current);
        }
      }
      return "\\"" + escaped + "\\"";
    }
  }
}
`,
    'utf8'
  );
}

function buildSpringRequestPayload(request) {
  const body =
    request.body?.encoding === 'base64' &&
    typeof request.body.value === 'string'
      ? request.body.value
      : '';
  return [
    `method=${request.method ?? 'GET'}`,
    `path=${request.path ?? '/'}`,
    `query=${request.query ?? ''}`,
    `body=${body}`,
  ].join('\n');
}

function isMissingJavaToolchain(errorOrMessage) {
  const message =
    typeof errorOrMessage === 'string'
      ? errorOrMessage
      : errorOrMessage instanceof Error
      ? `${errorOrMessage.message} ${String(errorOrMessage.cause ?? '')}`
      : String(errorOrMessage);
  const normalized = message.toLowerCase();
  return (
    normalized.includes('unable to locate a java runtime') ||
    normalized.includes('spawn javac enoent') ||
    normalized.includes('spawn java enoent') ||
    normalized.includes('command not found')
  );
}

function normalizeSpringPath(value) {
  if (!value || value === '/') {
    return '/';
  }
  const normalized = value.startsWith('/') ? value : `/${value}`;
  return normalized.endsWith('/') && normalized.length > 1
    ? normalized.slice(0, -1)
    : normalized;
}

function joinSpringPath(prefix, child) {
  const normalizedPrefix = normalizeSpringPath(prefix);
  const normalizedChild = normalizeSpringPath(child);
  if (normalizedPrefix === '/') {
    return normalizedChild;
  }
  if (normalizedChild === '/') {
    return normalizedPrefix;
  }
  return `${normalizedPrefix}${normalizedChild}`;
}

function parseSpringAnnotationPath(argumentsSource) {
  if (!argumentsSource) {
    return '';
  }

  const pathMatch =
    /(?:path|value)\s*=\s*"([^"]*)"/.exec(argumentsSource) ??
    /^"([^"]*)"$/.exec(argumentsSource.trim());
  return pathMatch?.[1] ?? '';
}

function splitJavaParameters(signature) {
  const parameters = [];
  let current = '';
  let depth = 0;
  let inString = false;

  for (let index = 0; index < signature.length; index += 1) {
    const char = signature[index];
    const previous = signature[index - 1];
    if (char === '"' && previous !== '\\') {
      inString = !inString;
    }

    if (!inString) {
      if (char === '(') {
        depth += 1;
      } else if (char === ')' && depth > 0) {
        depth -= 1;
      } else if (char === ',' && depth === 0) {
        if (current.trim()) {
          parameters.push(current.trim());
        }
        current = '';
        continue;
      }
    }

    current += char;
  }

  if (current.trim()) {
    parameters.push(current.trim());
  }

  return parameters;
}

function parseSpringParameter(parameterSource) {
  const source = parameterSource.trim();
  const pathVariableMatch =
    /@PathVariable\("([^"]+)"\)\s+([A-Za-z0-9_<>\[\]]+)\s+([A-Za-z0-9_]+)/.exec(
      source
    );
  if (pathVariableMatch) {
    return {
      binding: 'path',
      key: pathVariableMatch[1],
      name: pathVariableMatch[3],
      type: pathVariableMatch[2],
    };
  }

  const requestParamMatch =
    /@RequestParam\("([^"]+)"\)\s+([A-Za-z0-9_<>\[\]]+)\s+([A-Za-z0-9_]+)/.exec(
      source
    );
  if (requestParamMatch) {
    return {
      binding: 'query',
      key: requestParamMatch[1],
      name: requestParamMatch[3],
      type: requestParamMatch[2],
    };
  }

  const requestBodyMatch =
    /@RequestBody\s+([A-Za-z0-9_<>\[\]]+)\s+([A-Za-z0-9_]+)/.exec(source);
  if (requestBodyMatch) {
    return {
      binding: 'body',
      key: 'body',
      name: requestBodyMatch[2],
      type: requestBodyMatch[1],
    };
  }

  return null;
}

function matchSpringRoute(pattern, actualPath) {
  const names = [];
  const regex = new RegExp(
    `^${pattern.replace(/\{([A-Za-z_][A-Za-z0-9_]*)\}/g, (_, name) => {
      names.push(name);
      return '([^/]+)';
    })}$`
  );
  const match = regex.exec(actualPath);
  if (!match) {
    return null;
  }

  return Object.fromEntries(
    names.map((name, index) => [
      name,
      decodeURIComponent(match[index + 1] ?? ''),
    ])
  );
}

function decodeCompatibilityBody(body) {
  if (!body || body.encoding !== 'base64' || typeof body.value !== 'string') {
    return '';
  }
  return Buffer.from(body.value, 'base64').toString('utf8');
}

function encodeCompatibilityBody(body) {
  return {
    encoding: 'base64',
    value: Buffer.from(body, 'utf8').toString('base64'),
  };
}

function unescapeJavaStringLiteral(literal) {
  return literal
    .slice(1, -1)
    .replace(/\\\\/g, '\\')
    .replace(/\\"/g, '"')
    .replace(/\\n/g, '\n')
    .replace(/\\r/g, '\r')
    .replace(/\\t/g, '\t');
}

function splitJavaConcatExpression(expression) {
  const tokens = [];
  let current = '';
  let inString = false;

  for (let index = 0; index < expression.length; index += 1) {
    const char = expression[index];
    const previous = expression[index - 1];
    if (char === '"' && previous !== '\\') {
      inString = !inString;
    }

    if (!inString && char === '+') {
      if (current.trim()) {
        tokens.push(current.trim());
      }
      current = '';
      continue;
    }

    current += char;
  }

  if (current.trim()) {
    tokens.push(current.trim());
  }

  return tokens;
}

function evaluateSpringReturnExpression(methodBody, boundValues) {
  const returnMatch = /return\s+([^;]+);/s.exec(methodBody);
  if (!returnMatch) {
    return '';
  }

  const expression = returnMatch[1].trim();
  if (Object.prototype.hasOwnProperty.call(boundValues, expression)) {
    return String(boundValues[expression] ?? '');
  }

  return splitJavaConcatExpression(expression)
    .map((token) => {
      if (token.startsWith('"') && token.endsWith('"') && token.length >= 2) {
        return unescapeJavaStringLiteral(token);
      }

      return String(boundValues[token] ?? '');
    })
    .join('');
}

function parseSpringSourceRoutes(sourceText) {
  const classPrefixMatch =
    /@RequestMapping\(([\s\S]*?)\)\s*public\s+class/m.exec(sourceText);
  const classPrefix = normalizeSpringPath(
    parseSpringAnnotationPath(classPrefixMatch?.[1] ?? '')
  );
  const methodPattern =
    /((?:@\w+(?:\([^)]*\))?\s*)+)public\s+[A-Za-z0-9_<>\[\]]+\s+([A-Za-z0-9_]+)\s*\(([\s\S]*?)\)\s*\{([\s\S]*?)\n\s*\}/g;
  const routes = [];

  for (const match of sourceText.matchAll(methodPattern)) {
    const annotations = match[1] ?? '';
    const params = match[3] ?? '';
    const body = match[4] ?? '';

    const mappingMatch =
      /@(GetMapping|PostMapping|PutMapping|DeleteMapping|PatchMapping)\(([\s\S]*?)\)/.exec(
        annotations
      );
    if (!mappingMatch) {
      continue;
    }

    const method = mappingMatch[1]
      .replace('Mapping', '')
      .toUpperCase()
      .replace('DELETE', 'DELETE');
    const routePath = joinSpringPath(
      classPrefix,
      parseSpringAnnotationPath(mappingMatch[2])
    );
    const responseStatusMatch = /@ResponseStatus\(HttpStatus\.([A-Z_]+)\)/.exec(
      annotations
    );
    const statusCode =
      {
        OK: 200,
        CREATED: 201,
        BAD_REQUEST: 400,
        NOT_FOUND: 404,
      }[responseStatusMatch?.[1] ?? 'OK'] ?? 200;

    routes.push({
      method,
      path: routePath,
      parameters: splitJavaParameters(params)
        .map(parseSpringParameter)
        .filter(Boolean),
      body,
      statusCode,
    });
  }

  return routes;
}

async function executeCompatibilityFromSpringSource(sourcePath, compatibility) {
  const sourceText = await readFile(sourcePath, 'utf8');
  const routes = parseSpringSourceRoutes(sourceText);
  const request = compatibility.request;
  const requestPath = normalizeSpringPath(request.path ?? '/');

  for (const route of routes) {
    if (route.method !== String(request.method ?? 'GET').toUpperCase()) {
      continue;
    }

    const pathParams = matchSpringRoute(route.path, requestPath);
    if (!pathParams) {
      continue;
    }

    const query = new URLSearchParams((request.query ?? '').replace(/^\?/, ''));
    const requestBody = decodeCompatibilityBody(request.body);
    const boundValues = {};
    for (const parameter of route.parameters) {
      if (!parameter) {
        continue;
      }

      if (parameter.binding === 'path') {
        boundValues[parameter.name] = pathParams[parameter.key] ?? '';
        continue;
      }

      if (parameter.binding === 'query') {
        boundValues[parameter.name] = query.get(parameter.key) ?? '';
        continue;
      }

      if (parameter.binding === 'body') {
        boundValues[parameter.name] = requestBody;
      }
    }

    const responseBody = evaluateSpringReturnExpression(
      route.body,
      boundValues
    );
    const trimmedBody = responseBody.trim();

    return {
      value: {
        matched: true,
        response: {
          status: route.statusCode,
          headers: {
            'Content-Type':
              trimmedBody.startsWith('{') || trimmedBody.startsWith('[')
                ? 'application/json; charset=utf-8'
                : 'text/plain; charset=utf-8',
          },
          body: encodeCompatibilityBody(responseBody),
        },
      },
      stdout: '',
      stderr: '',
    };
  }

  return {
    value: {
      matched: false,
    },
    stdout: '',
    stderr: '',
  };
}

async function executeCompatibility(request) {
  const compatibility = request.compatibility;
  if (!compatibility) {
    throw new Error('missing compatibility request');
  }

  if (compatibility.family !== 'java-service') {
    throw new Error(
      `unsupported compatibility family ${JSON.stringify(compatibility.family)}`
    );
  }

  if (compatibility.framework !== 'spring') {
    throw new Error(
      `unsupported Java service framework ${JSON.stringify(
        compatibility.framework
      )}`
    );
  }

  const sourcePath = resolve(request.filePath);
  const sourceDir = dirname(sourcePath);
  const entryClassName = basename(sourcePath, '.java');

  const tempDir = await mkdtemp(join(tmpdir(), 'xgnosis-spring-compat-'));
  const sourceRoot = join(tempDir, 'src');
  const classesRoot = join(tempDir, 'classes');

  try {
    await mkdir(sourceRoot, { recursive: true });
    await mkdir(classesRoot, { recursive: true });

    await copyJavaSources(sourceDir, sourcePath, sourceRoot);
    await writeSpringShims(sourceRoot);
    await writeSpringWrapper(sourceRoot);

    const shimFiles = [];
    async function collect(dir) {
      const entries = await readdir(dir, { withFileTypes: true });
      for (const entry of entries) {
        const fullPath = join(dir, entry.name);
        if (entry.isDirectory()) {
          await collect(fullPath);
        } else if (entry.isFile() && extname(entry.name) === '.java') {
          shimFiles.push(fullPath);
        }
      }
    }

    await collect(sourceRoot);

    let compileResult;
    try {
      compileResult = await runCommand('javac', [
        '-d',
        classesRoot,
        ...shimFiles,
      ]);
    } catch (error) {
      if (isMissingJavaToolchain(error)) {
        return await executeCompatibilityFromSpringSource(
          sourcePath,
          compatibility
        );
      }
      throw error;
    }

    if (compileResult.code !== 0) {
      const compilerMessage = compileResult.stderr || compileResult.stdout;
      if (isMissingJavaToolchain(compilerMessage)) {
        return await executeCompatibilityFromSpringSource(
          sourcePath,
          compatibility
        );
      }
      throw new Error(`javac failed:\n${compilerMessage}`);
    }

    const requestPayload = Buffer.from(
      buildSpringRequestPayload(compatibility.request),
      'utf8'
    ).toString('base64');

    let runResult;
    try {
      runResult = await runCommand(
        'java',
        [
          '-cp',
          classesRoot,
          'XGnosisSpringCompatMain',
          entryClassName,
          requestPayload,
        ],
        { cwd: tempDir }
      );
    } catch (error) {
      if (isMissingJavaToolchain(error)) {
        return await executeCompatibilityFromSpringSource(
          sourcePath,
          compatibility
        );
      }
      throw error;
    }

    if (runResult.code !== 0) {
      const runtimeMessage = runResult.stderr || runResult.stdout;
      if (isMissingJavaToolchain(runtimeMessage)) {
        return await executeCompatibilityFromSpringSource(
          sourcePath,
          compatibility
        );
      }
      throw new Error(`java failed:\n${runtimeMessage}`);
    }

    return {
      value: JSON.parse(runResult.stdout.trim() || '{}'),
      stdout: '',
      stderr: runResult.stderr,
    };
  } finally {
    await rm(tempDir, { recursive: true, force: true });
  }
}

async function main() {
  const rawInput = await new Promise((resolveInput) => {
    let input = '';
    process.stdin.setEncoding('utf8');
    process.stdin.on('data', (chunk) => {
      input += chunk;
    });
    process.stdin.on('end', () => resolveInput(input));
  });

  if (!rawInput.trim()) {
    writeError('empty input');
    return;
  }

  let request;
  try {
    request = JSON.parse(rawInput);
  } catch (error) {
    writeError(
      `invalid JSON input: ${
        error instanceof Error ? error.message : String(error)
      }`
    );
    return;
  }

  if (request.action === 'ping') {
    writeResponse({
      status: 'ok',
      value: 'pong',
      stdout: '',
      stderr: '',
    });
    return;
  }

  try {
    if (request.compatibility) {
      const result = await executeCompatibility(request);
      writeResponse({
        status: 'ok',
        value: result.value,
        stdout: result.stdout,
        stderr: result.stderr,
      });
      return;
    }

    writeError(
      'java direct function execution is not implemented in the dedicated harness'
    );
  } catch (error) {
    writeError(error instanceof Error ? error.message : String(error));
  }
}

await main();
